import clsx from 'clsx';
import { memo } from 'react';
import { useIntl } from 'react-intl';

import { formatTimeframeToParts } from '@dynatrace-sdk/units';

import { DataTestId } from '../../../../../core/types/data-props.js';
import { StylingProps } from '../../../../../core/types/styling-props.js';

/**
 * Component properties interface for the {@link FormattedTimeframe} component.
 * @internal
 */
export interface FormattedTimeframeProps extends StylingProps, DataTestId {
  /** Start date of the timeframe. */
  from: Date;
  /** End date of the timeframe. */
  to: Date;
  /** If true, the 'to' date will be clamped to 'now' if it is in the future. */
  clampFutureToDateToNow?: boolean;
}

/**
 * Component to format a timeframe leveraging React Intl APIs.
 *
 * @internal
 */
export const FormattedTimeframe = memo((props: FormattedTimeframeProps) => {
  const intl = useIntl();
  const {
    from,
    to,
    clampFutureToDateToNow,
    className: consumerClassName,
    style: consumerStyle,
    'data-testid': dataTestId,
  } = props;
  const parts = formatTimeframeToParts(from, to, intl, clampFutureToDateToNow);
  return typeof parts === 'string' ? (
    <span
      data-testid={dataTestId}
      className={clsx('formatted-timeframe', consumerClassName)}
      style={consumerStyle}
    >
      {parts}
    </span>
  ) : (
    <span
      data-testid={dataTestId}
      className={clsx('formatted-timeframe', consumerClassName)}
      style={consumerStyle}
    >
      <span className="ft-prefix">{parts[0]}</span>
      <span className="ft-separator">&nbsp;{parts[1]}&nbsp;</span>
      <span className="ft-suffix">{parts[2]}</span>
    </span>
  );
});
